What does this program print?

```cpp
#include <iostream>
void changePtr(int* p, int* other) {
    p = other;
}
int main() {
    int a { 10 }, b { 20 };
    int* ptr { &a };
    changePtr(ptr, &b);
    std::cout << *ptr << '\n';
    return 0;
}
```

The function is supposed to reset the caller's pointer to `nullptr`, but it doesn't work. What is the bug?

```cpp
#include <iostream>
void resetToNull(int* ptr) {
    ptr = nullptr;
}
int main() {
    int x { 5 };
    int* p { &x };
    resetToNull(p);
    std::cout << (p == nullptr ? "null" : "not null") << '\n';
    return 0;
}
```

